import { useState } from "react"
import { useNavigate, Link } from "react-router-dom"
import { useDispatch } from "react-redux"
import { userApi } from "../api/axios"
import { setCredentials } from "../store/slices/authSlice"

export default function Login() {
  const dispatch = useDispatch()
  const [email, setEmail] = useState("")
  const [password, setPassword] = useState("")
  const navigate = useNavigate()

  const handleSubmit = async (e) => {
    e.preventDefault()

    try {
      const formData = new URLSearchParams()
      formData.append("username", email)
      formData.append("password", password)

      const res = await userApi.post("/auth/login", formData, {
        headers: {
          "Content-Type": "application/x-www-form-urlencoded",
        },
      })

      const token = res.data.access_token

      const meRes = await userApi.get("/auth/me", {
        headers: {
          Authorization: `Bearer ${token}`,
        },
      })

      dispatch(
        setCredentials({
          token,
          role: "user",
          displayName: meRes.data?.name || "User",
          profilePicture: meRes.data?.profile_picture || "",
        })
      )

      navigate("/")
    } catch (err) {
      console.error(err)
      alert("Login failed")
    }
  }

  return (
    <div className="auth-page">
      <div className="auth-card">
        <h1>User Login</h1>
        <p>Log in to continue exploring restaurants</p>

        <form onSubmit={handleSubmit} className="auth-form">
          <input
            type="email"
            placeholder="Email address"
            value={email}
            onChange={(e) => setEmail(e.target.value)}
          />
          <input
            type="password"
            placeholder="Password"
            value={password}
            onChange={(e) => setPassword(e.target.value)}
          />
          <button type="submit" className="btn btn-primary full-width">
            Log In
          </button>
        </form>

        <div className="auth-footer">
          <span>New here?</span>
          <Link to="/signup">Create account</Link>
        </div>
      </div>
    </div>
  )
}
